const body = $input.first().json.body || $input.first().json;
const videoDir  = (body.video_dir  || '').replace(/\\/g, '/').replace(/\/$/, '');
const outputDir = (body.output_dir || videoDir).replace(/\\/g, '/').replace(/\/$/, '');
const threshold = body.quality_threshold || 0.75;
const fs = require('fs');
if (!fs.existsSync(videoDir)) throw new Error('Folder not found: ' + videoDir);
const files = fs.readdirSync(videoDir)
  .filter(function(f) { return /\.(mp4|mov|avi|mkv|webm|m4v)$/i.test(f); })
  .map(function(f) { return { filename: f, filepath: videoDir + '/' + f, videoDir: videoDir, outputDir: outputDir, threshold: threshold }; });
if (files.length === 0) throw new Error('No video files found in: ' + videoDir);
return files;

const items = $input.all();
const { execSync } = require('child_process');
var results = [];
for (var j = 0; j < items.length; j++) {
  var item = items[j].json;
  var probe;
  try {
    var out = execSync('"C:\\ffmpeg\\bin\\ffprobe.exe" -v quiet -print_format json -show_streams -show_format "' + item.filepath + '"', { encoding: 'utf8', timeout: 30000, shell: true });
    probe = JSON.parse(out);
  } catch(e) { throw new Error('ffprobe failed for ' + item.filename + ': ' + e.message); }
  var vs  = (probe.streams || []).find(function(s) { return s.codec_type === 'video'; }) || {};
  var as_ = (probe.streams || []).find(function(s) { return s.codec_type === 'audio'; }) || {};
  var fmt = probe.format || {};
  var fps = 0;
  if (vs.r_frame_rate) { var p = vs.r_frame_rate.split('/'); fps = p.length === 2 ? parseFloat(p[0])/parseFloat(p[1]) : parseFloat(p[0]); }
  results.push({ json: { filename: item.filename, filepath: item.filepath, videoDir: item.videoDir, outputDir: item.outputDir, threshold: item.threshold, metadata: {
    duration_sec: parseFloat(fmt.duration || 0), size_bytes: parseInt(fmt.size || 0), bitrate: parseInt(fmt.bit_rate || 0),
    fps: parseFloat(fps.toFixed(2)), width: vs.width || 0, height: vs.height || 0,
    video_codec: vs.codec_name || 'unknown', audio_codec: as_.codec_name || 'none', has_audio: !!as_.codec_name
  }}});
}
return results;

const items = $input.all();
const { execSync } = require('child_process');
const fs = require('fs');
const os = require('os');
var tmpDir = os.tmpdir().replace(/\\/g, '/');
var results = [];
for (var j = 0; j < items.length; j++) {
  var item = items[j].json;
  var dur = item.metadata.duration_sec;
  var base = item.filename.replace(/\.[^.]+$/, '').replace(/[^a-zA-Z0-9_-]/g, '_');
  var times = [0, dur*0.25, dur*0.5, dur*0.75].map(function(t) { return parseFloat(t.toFixed(2)); });
  var frames = [];
  for (var i = 0; i < times.length; i++) {
    var ts = times[i];
    var out = tmpDir + '/' + base + '_frame_' + i + '.jpg';
    try {
      execSync('"C:\\ffmpeg\\bin\\ffmpeg.exe" -y -ss ' + ts + ' -i "' + item.filepath + '" -vframes 1 -q:v 3 "' + out + '"', { timeout: 20000, shell: true, stdio: 'pipe' });
      if (fs.existsSync(out)) { frames.push({ timestamp_sec: ts, base64: fs.readFileSync(out).toString('base64') }); fs.unlinkSync(out); }
    } catch(e) {}
  }
  if (frames.length === 0) throw new Error('Could not extract frames from: ' + item.filename);
  results.push({ json: Object.assign({}, item, { frames: frames }) });
}
return results;

const items = $input.all();
var results = [];
for (var j = 0; j < items.length; j++) {
  var item = items[j].json;
  var meta = item.metadata;
  var imageMessages = item.frames.map(function(f) { return { type: 'image_url', image_url: { url: 'data:image/jpeg;base64,' + f.base64, detail: 'low' } }; });
  var userPrompt = 'Analyse these ' + item.frames.length + ' frames from a ' + meta.duration_sec.toFixed(1) + 's video.\n' +
    'Metadata: ' + meta.width + 'x' + meta.height + ' @ ' + meta.fps + 'fps, codec=' + meta.video_codec + ', has_audio=' + meta.has_audio + '.\n\n' +
    'Return ONLY this JSON, no markdown:\n{"overall_score":<float 0-1>,"issues":[<string>],"good_segments":[{"start_pct":<0-1>,"end_pct":<0-1>,"reason":<string>}],"bad_segments":[{"start_pct":<0-1>,"end_pct":<0-1>,"reason":<string>}],"recommendation":"keep" or "trim" or "discard","notes":<string>}';
  var payload = { model: 'gpt-4o', max_tokens: 800, messages: [
    { role: 'system', content: 'You are a professional video quality analyst. Return ONLY valid JSON, no markdown.' },
    { role: 'user', content: [{ type: 'text', text: userPrompt }].concat(imageMessages) }
  ]};
  results.push({ json: Object.assign({}, item, { gpt4o_payload: payload }) });
}
return results;

const allPrev = $('Build GPT-4o Quality Request').all();
const allResp = $input.all();
var results = [];
for (var j = 0; j < allResp.length; j++) {
  var prev = (allPrev[j] || allPrev[0]).json;
  var resp = allResp[j].json;
  var analysis;
  try { var raw = resp.choices[0].message.content.trim(); analysis = JSON.parse(raw.replace(/^```json\n?|^```\n?|```$/gm,'').trim()); }
  catch(e) { analysis = { overall_score: 0.5, recommendation: 'keep', good_segments: [{ start_pct: 0, end_pct: 1, reason: 'fallback' }], issues: [], notes: '' }; }
  if (analysis.recommendation === 'discard') {
    analysis.recommendation = 'keep';
    analysis.good_segments = [{ start_pct: 0, end_pct: 1, reason: 'forced include - override discard' }];
  }
  var dur = prev.metadata.duration_sec;
  var goodSegments = (analysis.good_segments && analysis.good_segments.length > 0)
    ? analysis.good_segments.map(function(s) { return { start: parseFloat((s.start_pct*dur).toFixed(2)), end: parseFloat((s.end_pct*dur).toFixed(2)), reason: s.reason||'' }; })
    : [{ start: 0, end: dur, reason: 'full video' }];
  results.push({ json: Object.assign({}, prev, { analysis: analysis, goodSegments: goodSegments, qualityScore: analysis.overall_score, recommendation: analysis.recommendation }) });
}
return results;

const items = $input.all();
const { execSync } = require('child_process');
const fs = require('fs');
const os = require('os');
var tmpDir = os.tmpdir().replace(/\\/g, '/');
var results = [];
for (var j = 0; j < items.length; j++) {
  var item = items[j].json;
  var base = item.filename.replace(/\.[^.]+$/, '').replace(/[^a-zA-Z0-9_-]/g, '_');
  for (var i = 0; i < item.goodSegments.length; i++) {
    var seg = item.goodSegments[i];
    var out = tmpDir + '/' + base + '_clip_' + i + '.mp4';
    var cmd = '"C:\\ffmpeg\\bin\\ffmpeg.exe" -y -ss ' + seg.start + ' -to ' + seg.end + ' -i "' + item.filepath + '" -c:v libx264 -preset fast -crf 18 -c:a aac -b:a 192k "' + out + '"';
    try {
      execSync(cmd, { stdio: 'pipe', timeout: 300000, shell: true });
      if (fs.existsSync(out) && fs.statSync(out).size > 0) results.push({ json: Object.assign({}, item, { clip: { clipPath: out, start: seg.start, end: seg.end, duration: parseFloat((seg.end-seg.start).toFixed(2)), reason: seg.reason, sourceFile: item.filename, qualityScore: item.qualityScore } }) });
    } catch(e) { console.error('Clip ' + i + ' from ' + item.filename + ' failed: ' + e.message); }
  }
}
if (results.length === 0) throw new Error('No clips produced from any video.');
return results;

const raw = $input.all().map(function(i) { return i.json; });
const allClips = raw.reduce(function(acc, item) {
  if (item.data && Array.isArray(item.data)) { return acc.concat(item.data); }
  return acc.concat([item]);
}, []);
const summaries = allClips.map(function(item, idx) { return { index: idx, source: item.clip ? item.clip.sourceFile : item.filename, clip_path: item.clip ? item.clip.clipPath : item.filepath, duration_sec: item.clip ? item.clip.duration : (item.metadata ? item.metadata.duration_sec : 0), quality_score: item.clip ? item.clip.qualityScore : (item.qualityScore||0), reason: item.clip ? item.clip.reason : '' }; });
const payload = { model: 'gpt-4o', max_tokens: 600, messages: [
  { role: 'system', content: 'You are a professional video editor. Return ONLY valid JSON, no markdown.' },
  { role: 'user', content: 'Arrange these ' + summaries.length + ' clips into the best final video.\nClips:\n' + JSON.stringify(summaries,null,2) + '\n\nReturn ONLY: {"ordered_indices":[<int>...],"reasoning":<string>,"estimated_total_duration_sec":<float>}\nExclude clips with quality_score < 0.3.' }
]};
return [{ json: { allClips: allClips, clipSummaries: summaries, gpt4o_rank_payload: payload } }];

const prev = $('Build Ranking Request').first().json;
const fs = require('fs');
const os = require('os');
var tmpDir = os.tmpdir().replace(/\\/g, '/');
function getFileNumber(filename) {
  var match = (filename || '').match(/(\d+)/);
  return match ? parseInt(match[1], 10) : 999999;
}
var allClips = prev.allClips;
var clipSummaries = prev.clipSummaries;
var indexed = allClips.map(function(c, idx) {
  var source = c.clip ? c.clip.sourceFile : (c.filename || '');
  var clipPath = c.clip ? c.clip.clipPath : c.filepath;
  var score = clipSummaries[idx] ? clipSummaries[idx].quality_score : 0;
  return { idx: idx, clipPath: clipPath, source: source, score: score, fileNum: getFileNumber(source) };
});
indexed.sort(function(a, b) { return a.fileNum - b.fileNum; });
var orderedClips = indexed.filter(function(c) { return fs.existsSync(c.clipPath); });
if (orderedClips.length === 0) throw new Error('No valid clips for merging.');
var listPath = tmpDir + '/concat_list.txt';
fs.writeFileSync(listPath, orderedClips.map(function(c) { return "file '" + c.clipPath + "'"; }).join('\n'));
var first = allClips[0];
var outputDir = (first.outputDir || first.videoDir || tmpDir).replace(/\\/g, '/');
var outputPath = outputDir + '/final_edited_' + new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19) + '.mp4';
return [{ json: { allClips: allClips, clipSummaries: clipSummaries, orderedClips: orderedClips, ranking: { reasoning: 'sorted by filename number ascending', ordered_indices: orderedClips.map(function(c){return c.idx;}) }, listPath: listPath, outputPath: outputPath, outputDir: outputDir } }];

const item = $input.first().json;
const { execSync } = require('child_process');
const fs = require('fs');
var cmd = '"C:\\ffmpeg\\bin\\ffmpeg.exe" -y -f concat -safe 0 -i "' + item.listPath + '" -c:v libx264 -preset medium -crf 18 -c:a aac -b:a 192k -movflags +faststart "' + item.outputPath + '"';
try { execSync(cmd, { stdio: 'pipe', timeout: 600000, shell: true }); } catch(e) { throw new Error('ffmpeg merge failed: ' + e.message); }
if (!fs.existsSync(item.outputPath)) throw new Error('Output not created: ' + item.outputPath);
var sizeMb = parseFloat((fs.statSync(item.outputPath).size/1024/1024).toFixed(2));
item.orderedClips.forEach(function(c){try{fs.unlinkSync(c.clipPath);}catch(e){}});
try{fs.unlinkSync(item.listPath);}catch(e){}
return [{ json: Object.assign({}, item, { mergeComplete: true, output_file_size_mb: sizeMb }) }];

const item = $input.first().json;
const { execSync } = require('child_process');
const fs = require('fs');
const os = require('os');
var finalMeta = {};
try {
  var probe = JSON.parse(execSync('"C:\\ffmpeg\\bin\\ffprobe.exe" -v quiet -print_format json -show_streams -show_format "' + item.outputPath + '"', { encoding: 'utf8', timeout: 30000, shell: true }));
  var vs = (probe.streams||[]).find(function(s){return s.codec_type==='video';})||{};
  var fmt = probe.format||{};
  var fps=0; if(vs.r_frame_rate){var p=vs.r_frame_rate.split('/');fps=p.length===2?parseFloat(p[0])/parseFloat(p[1]):parseFloat(p[0]);}
  finalMeta = { duration_sec: parseFloat(fmt.duration||0), fps: parseFloat(fps.toFixed(2)), width: vs.width||0, height: vs.height||0 };
} catch(e) {}
var dur = finalMeta.duration_sec||10;
var tmpDir = os.tmpdir().replace(/\\/g,'/');
var frames = [];
for (var i=0;i<3;i++) {
  var ts = dur*(0.2+i*0.3);
  var out = tmpDir+'/final_val_'+i+'.jpg';
  try { execSync('"C:\\ffmpeg\\bin\\ffmpeg.exe" -y -ss '+ts.toFixed(2)+' -i "'+item.outputPath+'" -vframes 1 -q:v 3 "'+out+'"',{timeout:20000,shell:true,stdio:'pipe'}); if(fs.existsSync(out)){frames.push({base64:fs.readFileSync(out).toString('base64')});fs.unlinkSync(out);} } catch(e){}
}
return [{ json: Object.assign({}, item, { finalMeta: finalMeta, validationFrames: frames }) }];

const item = $input.first().json;
const imgs = item.validationFrames.map(function(f){return{type:'image_url',image_url:{url:'data:image/jpeg;base64,'+f.base64,detail:'low'}};});
const prompt = 'Review this final merged video.\nSpecs: '+item.finalMeta.width+'x'+item.finalMeta.height+', '+(item.finalMeta.duration_sec||0).toFixed(1)+'s, '+(item.orderedClips||[]).length+' clips, '+item.output_file_size_mb+' MB.\nReturn ONLY: {"validation_score":<0-1>,"passed":<bool>,"continuity_ok":<bool>,"audio_sync_ok":<bool>,"visual_quality_ok":<bool>,"issues_found":[<string>],"suggestions":[<string>],"verdict":"approved" or "needs_revision" or "rejected"}';
const payload = { model: 'gpt-4o', max_tokens: 600, messages: [
  { role: 'system', content: 'You are a professional video QA reviewer. Return ONLY valid JSON, no markdown.' },
  { role: 'user', content: [{type:'text',text:prompt}].concat(imgs) }
]};
return [{ json: Object.assign({}, item, { gpt4o_validate_payload: payload }) }];

const resp = $input.first().json;
const prev = $('Build Validation Request').first().json;
var v;
try { v = JSON.parse(resp.choices[0].message.content.trim().replace(/^```json\n?|^```\n?|```$/gm,'').trim()); }
catch(e) { v = { validation_score:0.5, passed:true, verdict:'approved', issues_found:[], suggestions:[], continuity_ok:true, audio_sync_ok:true, visual_quality_ok:true }; }
return [{ json: {
  status: v.verdict==='rejected'?'FAILED':'SUCCESS',
  verdict: v.verdict, validation_score: v.validation_score,
  output_file: prev.outputPath, output_size_mb: prev.output_file_size_mb,
  final_duration_sec: prev.finalMeta?prev.finalMeta.duration_sec:null,
  clips_merged: prev.orderedClips?prev.orderedClips.length:null,
  source_videos: prev.allClips?prev.allClips.length:null,
  continuity_ok: v.continuity_ok, audio_sync_ok: v.audio_sync_ok, visual_quality_ok: v.visual_quality_ok,
  issues: v.issues_found||[], suggestions: v.suggestions||[],
  ai_ranking_reason: prev.ranking?prev.ranking.reasoning:'',
  completed_at: new Date().toISOString()
}}];
